#include <iostream>
#include <vector>
#include <memory>
#include <iomanip>
#include <cmath>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

int main() {
    std::cout << std::fixed << std::setprecision(3);

    // Create objects using smart pointers for polymorphic behavior
    std::vector<std::unique_ptr<Shape>> shapes;
    shapes.push_back(std::make_unique<Rectangle>(5.0, 10.0));
    shapes.push_back(std::make_unique<Rectangle>(2.5, 4.0));
    shapes.push_back(std::make_unique<Circle>(7.0));
    shapes.push_back(std::make_unique<Circle>(1.0));

    for (const auto& shape : shapes) {
        std::cout << "Area: " << shape->getArea() << std::endl;
    }

    return 0;
}
